function lengthOfLongestSubstring(s) {
  let longest = 0;

  for (let left = 0; left < s.length; left++) {
    const seen = new Set();
    for (let right = left; right < s.length; right++) {
      const ch = s[right];
      if (seen.has(ch)) break;
      seen.add(ch);
      longest = Math.max(longest, right - left + 1);
    }
  }

  return longest;
}

